const mergedCustomer = $("Parse Lead Analysis").all()[0].json;
const openAiOutput = $("Personalization Agent").all()[0].json;

const personalization = findPersonalization(openAiOutput);

if (!personalization) {
  throw new Error("Could not find personalization fields in Personalization Agent output.");
}

return [
  {
    json: {
      ...mergedCustomer,
      ...personalization
    }
  }
];
